### Redaction Report

```rust
pub struct RedactionReport {
    pub total_redactions: usize,
    pub by_kind: HashMap<RedactionKind, usize>,
    pub samples: Vec<RedactionSample>,
}

pub struct RedactionSample {
    pub kind: RedactionKind,
    pub context: String,  // Surrounding text
    pub before: String,
    pub after: String,
}

impl RedactionEngine {
    pub fn generate_report(&self, hits: &[SearchHit]) -> RedactionReport {
        let mut report = RedactionReport::default();

        for hit in hits {
            let title_result = self.redact(&hit.title);
            let content_result = self.redact(&hit.content);

            for change in title_result.changes.iter().chain(&content_result.changes) {
                *report.by_kind.entry(change.kind.clone()).or_insert(0) += 1;
                report.total_redactions += 1;

                if report.samples.len() < 10 {
                    report.samples.push(RedactionSample {
                        kind: change.kind.clone(),
                        context: extract_context(&hit.content, &change.original),
                        before: change.original.clone(),
                        after: change.redacted.clone(),
                    });
                }
            }
        }

        report
    }
}
